256	fn len() {
257	    const COUNT: usize = if cfg!(miri) { 50 } else { 25_000 };
258	    const CAP: usize = if cfg!(miri) { 50 } else { 1000 };
259	
260	    let (s, r) = bounded(CAP);
261	
262	    assert_eq!(s.len(), 0);
263	    assert_eq!(r.len(), 0);
264	
265	    for _ in 0..CAP / 10 {
266	        for i in 0..50 {
267	            s.send(i).unwrap();
268	            assert_eq!(s.len(), i + 1);
269	        }
270	
271	        for i in 0..50 {
272	            r.recv().unwrap();
273	            assert_eq!(r.len(), 50 - i - 1);
274	        }
275	    }
276	
277	    assert_eq!(s.len(), 0);
278	    assert_eq!(r.len(), 0);
279	
280	    for i in 0..CAP {
281	        s.send(i).unwrap();
282	        assert_eq!(s.len(), i + 1);
283	    }
284	
285	    for _ in 0..CAP {
286	        r.recv().unwrap();
287	    }
288	
289	    assert_eq!(s.len(), 0);
290	    assert_eq!(r.len(), 0);
291	
292	    scope(|scope| {
293	        scope.spawn(|_| {
294	            for i in 0..COUNT {
295	                assert_eq!(r.recv(), Ok(i));
296	                let len = r.len();
297	                assert!(len <= CAP);
298	            }
299	        });
300	
301	        scope.spawn(|_| {
302	            for i in 0..COUNT {
303	                s.send(i).unwrap();
304	                let len = s.len();
305	                assert!(len <= CAP);
306	            }
307	        });
308	    })
309	    .unwrap();
310	
311	    assert_eq!(s.len(), 0);
312	    assert_eq!(r.len(), 0);
313	}
