659	#[test]
660	fn panic_on_drop() {
661	    struct Msg1<'a>(&'a mut bool);
662	    impl Drop for Msg1<'_> {
663	        fn drop(&mut self) {
664	            if *self.0 && !std::thread::panicking() {
665	                panic!("double drop");
666	            } else {
667	                *self.0 = true;
668	            }
669	        }
670	    }
671	
672	    struct Msg2<'a>(&'a mut bool);
673	    impl Drop for Msg2<'_> {
674	        fn drop(&mut self) {
675	            if *self.0 {
676	                panic!("double drop");
677	            } else {
678	                *self.0 = true;
679	                panic!("first drop");
680	            }
681	        }
682	    }
683	
684	    // normal
685	    let (s, r) = bounded(2);
686	    let (mut a, mut b) = (false, false);
687	    s.send(Msg1(&mut a)).unwrap();
688	    s.send(Msg1(&mut b)).unwrap();
689	    drop(s);
690	    drop(r);
691	    assert!(a);
692	    assert!(b);
693	
694	    if option_env!("MIRI_LEAK_CHECK").is_some() || option_env!("ASAN_OPTIONS").is_some() {
695	        return;
696	    }
697	
698	    // panic on drop
699	    let (s, r) = bounded(2);
700	    let (mut a, mut b) = (false, false);
701	    s.send(Msg2(&mut a)).unwrap();
702	    s.send(Msg2(&mut b)).unwrap();
703	    drop(s);
704	    let res = std::panic::catch_unwind(move || {
705	        drop(r);
706	    });
707	    assert_eq!(
708	        *res.unwrap_err().downcast_ref::<&str>().unwrap(),
709	        "first drop"
710	    );
711	    assert!(a);
712	    // Elements after the panicked element will leak.
713	    assert!(!b);
714	}
