716	#[test]
717	fn drop_unreceived() {
718	    let (tx, rx) = bounded::<Rc<()>>(1);
719	    let msg = Rc::new(());
720	    let weak = Rc::downgrade(&msg);
721	    assert!(tx.send(msg).is_ok());
722	    drop(rx);
723	    // Messages should be dropped immediately when the last receiver is destroyed.
724	    assert!(weak.upgrade().is_none());
725	    drop(tx);
726	}
