#[test]
fn test_nonblock_recv_race() {
    const N: usize = if cfg!(miri) { 100 } else { 1000 };

    for _ in 0..N {
        let c = make::<i32>(1);
        c.send(1);

        let t = go!(c, {
            select! {
                recv(c.rx()) -> _ => {}
                default => panic!("chan is not ready"),
            }
        });

        c.close_s();
        c.recv();
        t.join().unwrap();
    }
}

#[test]
fn test_nonblock_select_race() {
    const N: usize = if cfg!(miri) { 100 } else { 1000 };

    let done = make::<bool>(1);
    for _ in 0..N {
        let c1 = make::<i32>(1);
        let c2 = make::<i32>(1);
        c1.send(1);

        go!(c1, c2, done, {
            select! {
                recv(c1.rx()) -> _ => {}
                recv(c2.rx()) -> _ => {}
                default => {
                    done.send(false);
                    return;
                }
            }
            done.send(true);
        });

        c2.send(1);
        select! {
            recv(c1.rx()) -> _ => {}
            default => {}
        }
        if !done.recv().unwrap() {
            panic!("no chan is ready");
        }
    }
}

