fn stress() {
    const COUNT: usize = if cfg!(miri) { 100 } else { 10000 };

    let (tx, rx) = channel::<i32>();
    let t = thread::spawn(move || {
        for _ in 0..COUNT {
            tx.send(1).unwrap();
        }
    });
    for _ in 0..COUNT {
        assert_eq!(rx.recv().unwrap(), 1);
    }
    t.join().unwrap();
}

#[test]
fn stress_shared() {
    let amt: u32 = if cfg!(miri) { 100 } else { 10_000 };
    let nthreads: u32 = if cfg!(miri) { 4 } else { 8 };
    let (tx, rx) = channel::<i32>();
